package middleware

import (
	"net/http"
	"sync"
	"time"
)

const (
	maxRequestsPerMinute = 100
	burstSize            = 20
	cleanupInterval      = 5 * time.Minute
	banDuration          = 15 * time.Minute
	banThreshold         = 3
)

type RateLimiter struct {
	mu       sync.Mutex
	clients  map[string]*clientState
}

type clientState struct {
	tokens    int
	lastSeen  time.Time
	violations int
	bannedUntil time.Time
}

func (rl *RateLimiter) Allow(ip string) bool {
	rl.mu.Lock()
	defer rl.mu.Unlock()

	client, exists := rl.clients[ip]
	if !exists {
		rl.clients[ip] = &clientState{tokens: burstSize, lastSeen: time.Now()}
		return true
	}

	if time.Now().Before(client.bannedUntil) {
		return false
	}

	elapsed := time.Since(client.lastSeen)
	refill := int(elapsed.Minutes() * float64(maxRequestsPerMinute))
	client.tokens = min(client.tokens+refill, burstSize)
	client.lastSeen = time.Now()

	if client.tokens <= 0 {
		client.violations++
		if client.violations >= banThreshold {
			client.bannedUntil = time.Now().Add(banDuration)
		}
		return false
	}

	client.tokens--
	return true
}
